package com.chaobo.scm.supplier.infrastructure.persistence.quality;import org.apache.ibatis.annotations.*;import java.time.*;import java.util.*;
@Mapper public interface SupplierQualityIssueMapper {record Row(long id,String no,long supplierId,String sourceType,String sourceNo,String issueType,int severity,String description,int status,OffsetDateTime deadline,String plan,String verification,int version){}@Select("SELECT quality_issue_id id,issue_no no,supplier_id supplierId,source_type sourceType,source_no sourceNo,issue_type issueType,severity,issue_description description,issue_status status,rectification_deadline deadline,rectification_plan plan,verification_comment verification,version FROM sup_quality_issue WHERE quality_issue_id=#{id} AND deleted=0")Row find(long id);@Insert("INSERT INTO sup_quality_issue(quality_issue_id,issue_no,supplier_id,source_type,source_no,issue_type,severity,issue_description,issue_status,rectification_deadline,rectification_plan,verification_comment,created_by,updated_by,version,deleted) VALUES(#{r.id},#{r.no},#{r.supplierId},#{r.sourceType},#{r.sourceNo},#{r.issueType},#{r.severity},#{r.description},#{r.status},#{r.deadline},#{r.plan},#{r.verification},#{operator},#{operator},#{r.version},0)")void insert(@Param("r")Row r,@Param("operator")long operator);@Update("UPDATE sup_quality_issue SET issue_status=#{r.status},rectification_deadline=#{r.deadline},rectification_plan=#{r.plan},verification_comment=#{r.verification},updated_by=#{operator},version=#{r.version} WHERE quality_issue_id=#{r.id} AND version=#{expected} AND deleted=0")int update(@Param("r")Row r,@Param("expected")int expected,@Param("operator")long operator);@Select("<script>SELECT COUNT(*) FROM sup_quality_issue WHERE deleted=0 <if test='supplierId!=null'>AND supplier_id=#{supplierId}</if><if test='status!=null'>AND issue_status=#{status}</if><if test='severity!=null'>AND severity=#{severity}</if></script>")long count(@Param("supplierId")Long supplierId,@Param("status")Integer status,@Param("severity")Integer severity);@Select("<script>SELECT quality_issue_id id,issue_no no,supplier_id supplierId,source_type sourceType,source_no sourceNo,issue_type issueType,severity,issue_description description,issue_status status,rectification_deadline deadline,rectification_plan plan,verification_comment verification,version FROM sup_quality_issue WHERE deleted=0 <if test='supplierId!=null'>AND supplier_id=#{supplierId}</if><if test='status!=null'>AND issue_status=#{status}</if><if test='severity!=null'>AND severity=#{severity}</if> ORDER BY updated_at DESC LIMIT #{offset},#{size}</script>")List<Row> page(@Param("supplierId")Long supplierId,@Param("status")Integer status,@Param("severity")Integer severity,@Param("offset")int offset,@Param("size")int size);@Select("SELECT quality_issue_id FROM sup_quality_issue WHERE issue_status=2 AND rectification_deadline<NOW(3) AND deleted=0")List<Long> overdueIds();}
